CREATE TABLE IF NOT EXISTS users (id SERIAL PRIMARY KEY, email VARCHAR(255) UNIQUE NOT NULL, password VARCHAR(255) NOT NULL, name VARCHAR(255), created_at TIMESTAMP DEFAULT NOW());
CREATE TABLE IF NOT EXISTS candidates (id SERIAL PRIMARY KEY, name VARCHAR(255) NOT NULL, email VARCHAR(255), experience_level VARCHAR(20) DEFAULT 'mid', skills TEXT, status VARCHAR(20) DEFAULT 'active', interviews_taken INTEGER DEFAULT 0, avg_score DECIMAL(4,1) DEFAULT 0, created_at TIMESTAMP DEFAULT NOW());
CREATE TABLE IF NOT EXISTS questions (id SERIAL PRIMARY KEY, title VARCHAR(255) NOT NULL, difficulty VARCHAR(20) DEFAULT 'medium', category VARCHAR(50), description TEXT, example_input TEXT, example_output TEXT, solution_hint TEXT, time_limit_min INTEGER DEFAULT 30, created_at TIMESTAMP DEFAULT NOW());
CREATE TABLE IF NOT EXISTS interviews (id SERIAL PRIMARY KEY, candidate_id INTEGER REFERENCES candidates(id) ON DELETE CASCADE, status VARCHAR(20) DEFAULT 'scheduled', difficulty VARCHAR(20) DEFAULT 'medium', score DECIMAL(4,1), feedback TEXT, duration_min INTEGER, questions_asked INTEGER DEFAULT 0, started_at TIMESTAMP, completed_at TIMESTAMP, created_at TIMESTAMP DEFAULT NOW());
CREATE TABLE IF NOT EXISTS submissions (id SERIAL PRIMARY KEY, interview_id INTEGER REFERENCES interviews(id) ON DELETE CASCADE, question_id INTEGER REFERENCES questions(id), code TEXT, language VARCHAR(20) DEFAULT 'javascript', score DECIMAL(4,1), feedback TEXT, time_taken_min INTEGER, created_at TIMESTAMP DEFAULT NOW());
CREATE TABLE IF NOT EXISTS interview_logs (id SERIAL PRIMARY KEY, interview_id INTEGER REFERENCES interviews(id), level VARCHAR(20) DEFAULT 'info', agent VARCHAR(50), message TEXT, created_at TIMESTAMP DEFAULT NOW());
